class Solution {
public:
    int binaryGap(int n) {
        int maxGap = 0, prev = -1;
        for (int i = 0; n; i++) {
            if (n & 1) {
                if (prev != -1) maxGap = max(maxGap, i - prev);
                prev = i;
            }
            n >>= 1;
        }
        return maxGap;
    }
};
